1	import { MantineProvider } from '@mantine/core';
2	import { screen } from '@testing-library/react';
3	import { ReactNode } from 'react';
4	
5	interface WrapperProps {
6	    children?: ReactNode;
7	}
8	
9	/**
10	 * In-memory colour scheme manager for tests to avoid touching runtime
11	 * localStorage and triggering Node experimental warnings.
12	 */
13	const testColorSchemeManager = {
14	    get: (defaultValue: 'auto' | 'dark' | 'light') => defaultValue,
15	    set: () => undefined,
16	    subscribe: () => undefined,
17	    unsubscribe: () => undefined,
18	    clear: () => undefined,
19	};
20	
21	/**
22	 * Test wrapper component that provides Mantine theming context.
23	 * Wraps children with MantineProvider configured for light color scheme.
24	 *
25	 * @param props - The component props
26	 * @param props.children - React nodes to be wrapped with Mantine provider
27	 * @returns A React component with Mantine provider context
28	 */
29	export const Wrapper = ({ children }: WrapperProps) => {
30	    return (
31	        <MantineProvider colorSchemeManager={testColorSchemeManager} defaultColorScheme="light">
32	            {children}
33	        </MantineProvider>
34	    );
35	};
36	
37	/**
38	 * Extracts and parses props from a rendered element's text content. Each
39	 * standard mock is expected to render a single element whose text looks like:
40	 * `<div>{id}: {JSON.stringify(props)}</div>`, for example:
41	 * `<div>MyComponent: {"prop1":"value1"}</div>`.
42	 *
